export async function setAwardAssignment(eventCode: string, awardId: string, series: number, body: {team?: number, name?: string, comment?: string}) {
    (Object.keys(body) as Array<keyof typeof body>).forEach(key => body[key] === undefined && delete body[key])
    const res = await fetch(normalizeUrl(`/event/${eventCode}/awards/set_assignment/${awardId}/${series}`), {
        method: 'PUT',
        body: PermissiveURLSearchParams(body),
    })
    if(!res.ok) {
        throw new Error(`Failed to set award body: ${res.status}`);
    }
}

export async function submitTeamAwards(eventCode: string) {
    await fetch(normalizeUrl(`/event/${eventCode}/awards/team_awards_submitted`), {
        method: 'PUT',
    })
}

export async function unsubmitTeamAwards(eventCode: string) {
    await fetch(normalizeUrl(`/event/${eventCode}/awards/team_awards_submitted`), {
        method: 'DELETE',
    })
}


export async function getAwardPresentationContext(eventCode: string) {
    const res = await fetch(normalizeUrl(`/event/${eventCode}/awards/presentation_context`))
    if(!res.ok) {
        throw new Error(`Failed to get award presentation context: ${res.status}`);
    }
    return await res.json() as AwardPresentationContext;
}

export async function upsertScriptCustomizationEnabled(eventCode: string, key: string, enabled: boolean) {
    await fetch(normalizeUrl(`/event/${eventCode}/awards/script_customizations/${key}`), {
        method: 'PUT',
        body: new URLSearchParams({enabled: enabled.toString()}),
    })
}

export async function upsertScriptCustomizationContent(eventCode: string, key: string, content: string) {
    await fetch(normalizeUrl(`/event/${eventCode}/awards/script_customizations/${key}`), {
        method: 'PUT',
        body: new URLSearchParams({content}),
    })
}

export async function showBlank(eventCode: string) {
    await fetch(normalizeUrl(`/event/${eventCode}/awards/show_blank`), {
        method: 'POST',
    })
}

export async function showAward(eventCode: string, awardId: string, series?: number) {
    const params: Record<string, string> = {awardId}
    if(series !== undefined) {
        params['series'] = series.toString()
    }
    await fetch(normalizeUrl(`/event/${eventCode}/awards/show_award`), {
        method: 'POST',
        body: new URLSearchParams(params),
    })
}

export async function showAdvancement(eventCode: string, index?: number) {
    const params: Record<string, string> = {}
    if(index !== undefined) {
        params['index'] = index.toString()
    }
    await fetch(normalizeUrl(`/event/${eventCode}/awards/show_advancement`), {
        method: 'POST',
        body: new URLSearchParams(params),
    })
}


export const useAwardPresentationContext = (eventCode: string, queryInterval?: number) =>
    useQuery({
        queryKey: ["awardPresentationContext", eventCode],
        queryFn: async () => {
            const context = await getAwardPresentationContext(eventCode)
            const ret = {...context}
            ret.advancements = context.advancements.map(((a, idx) => ({...a, index: idx})));
            return ret
        },
        refetchInterval: queryInterval
    })