import {t} from "../i18n";
import {AdvancementStatus, Award, AwardAssignment, AwardId, CommonAdvancement} from "../javaTypes";

const labelsAward = [t`Winner`, t`Second Place`, t`Third Place`, t`Runner Up`];
const labelsSmallRobot = [t`Captain`, t`Partner`];
const labelsRobot = [t`Captain`, t`1<sup>st</sup> Pick`, t`2<sup>nd</sup> Pick`];
const labelsDean = [t`Congratulations`];
const labelsTopRanked = [1, 2, 3, 4, 5, 6].map(ranking => t`Rank ${ranking}`);

export function isRobotAward(award: Award) {
    return [AwardId.WINNER_ID, AwardId.FINALIST_ID, AwardId.DIVISION_WINNER, AwardId.DIVISION_FINALIST, AwardId.CONFERENCE_FINALIST_ID].includes(award.awardTypeId);
}

export function isDivisionAward(award: Award) {
    return [AwardId.DIVISION_WINNER, AwardId.DIVISION_FINALIST].includes(award.awardTypeId);
}

export function assignmentIsPopulated(assignment: AwardAssignment) {
    return assignment.team || assignment.name;
}

export function getAwardLabel(award: Award, series: number, count: number) {
    let labels = labelsAward;
    if (isRobotAward(award)) {
        labels = count < 3 ? labelsSmallRobot : labelsRobot;
    }
    if (AwardId.DEANSLIST_ID == award.awardTypeId) {
        labels = labelsDean;
    }
    if (AwardId.TOP_RANKED === award.awardTypeId) {
        labels = labelsTopRanked;
    }
    const idx = series - 1;
    return labels[idx >= labels.length ? labels.length - 1 : idx];
}

export function sortAndFilterAssignments<AA extends AwardAssignment>(award: Award, assignments: AA[]) {
    return assignments.filter(assignmentIsPopulated).toSorted((a, b) => isRobotAward(award) || AwardId.DEANSLIST_ID == award.awardTypeId ? (a.series - b.series) : (b.series - a.series));
}

export type AdvancementEntry = CommonAdvancement & { index?: number };
export function filterAdvancements(advancements: AdvancementEntry[], count: number) {
    const ret = []
    let i = 0, foundAdvancements = 0;
    for (; (i < advancements.length && foundAdvancements < count); i++) {
        if (advancements[i]) {
            ret.push(advancements[i])
            if (advancements[i].status == AdvancementStatus.FIRST && advancements[i].team > -1) {
                foundAdvancements++;
            }
        }
    }
    return ret
}