function StageDirection({children}: { children: ReactNode }) {
    return <div className={"text-muted ml-4"}><i>{children}</i></div>
}

function AwardScript({award, assignments, divisions}: { award: Award, assignments: AwardAssignment[], divisions: Record<string, string> }) {
    return <div className="award-item">
        <div className="mr-1 d-inline-block award-name"><b dangerouslySetInnerHTML={{__html: award.name}}></b></div>
        <p className="award-desc">
            <span dangerouslySetInnerHTML={{__html: award.script}}></span>
            {isDivisionAward(award) ? <><br/>From the {divisions[award.awardSubtypeId]} division:</> : null}
        </p>

        <div className="ml-5 award-winners">

        {sortAndFilterAssignments(award, assignments).map(aa => <div className="award-winner-item" key={aa.series}>
            <div className="award-place" dangerouslySetInnerHTML={{__html: getAwardLabel(award, aa.series, assignments.length)}}></div>
            <div className="award-winner">
                {aa.comment ? <>
                    {award.awardTypeId == AwardId.DEANSLIST_ID ? null : <div className="award-winner-comments-intro">
                        Here is what the Judges have to say about
                        the <span dangerouslySetInnerHTML={{__html: getAwardLabel(award, aa.series, assignments.length).toLowerCase()}}></span> of
                        this Award:
                    </div>}
                    <div className="award-winner-comments">{aa.comment}</div>
                </> : null}
                {award.isTeamAward ? "" : aa.name + " " + (aa.team ? " of Team " : "")}
                {aa.team ? aa.team.displayNumber + " " + aa.team.name + (aa.team.location ? " - from " + aa.team.location : "") : "" }</div>
            {award.awardTypeId == AwardId.COMPASS_ID && aa.series == 1 ? <StageDirection>Play compass winner video</StageDirection> : null}
        </div>)}
        </div>
    </div>
}

function OptionalChunk({
    children,
    ckey,
    customizations,
    label,
    isEditing,
 }: {
    children: ReactNode,
    ckey: string,
    customizations: Record<string, ScriptCustomization>
    label?: string,
    isEditing: boolean,
}) {
    const customization = customizations[ckey]
    const visible = !customization || (customization.enabled)
    const id = useId()

    const queryClient = useQueryClient()
    const mutation = useMutation({
        mutationFn: async (newState: boolean) => {
            await upsertScriptCustomizationEnabled(window.eventCode, ckey, newState)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({
                queryKey: ["awardPresentationContext", window.eventCode]
            })
        }
    })

    return <>
        {isEditing ? <Form.Check
                type="switch"
                id={id}
                label={"Show this section: " + (label || t`Optional`)}
                checked={visible}
                onChange={(e) => mutation.mutate(e.target.checked)}
        /> : null}
        {visible ? <div>
            {customization ? null : <StageDirection>{label || t`Optional`}</StageDirection>}
            {children}
        </div> : null}
    </>
}


function CustomText({
                         defaultText,
                         helpText,
                         ckey,
                         customizations,
                         wrapper = "span",
                         isEditing,
                     }: {
    defaultText: string,
    helpText?: string,
    ckey: string,
    customizations: Record<string, ScriptCustomization>,
    wrapper?: "span" | "div" | "p",
    isEditing: boolean,
}) {
    const customization = customizations[ckey]
    const Element = wrapper
    const [currentContent, setCurrentContent] = useState<string>()

    const queryClient = useQueryClient()
    const mutation = useMutation({
        mutationFn: async (newState: string) => {
            await upsertScriptCustomizationContent(window.eventCode, ckey, newState)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({
                queryKey: ["awardPresentationContext", window.eventCode]
            })
        }
    })
    const helpId = useId()

    useEffect(() => {
        setCurrentContent(customization ? customization.content : defaultText)
    }, [isEditing]);

    if(isEditing) {
        return <>
            <Form.Control as="textarea" aria-describedby={helpId} value={currentContent} onChange={(e) => setCurrentContent(e.target.value)} onBlur={() => mutation.mutate(currentContent || '')} placeholder={helpText}></Form.Control>
            <Form.Text id={helpId} muted>{helpText || defaultText}</Form.Text>
        </>
    }

    // If we have help text, the regular text should be shown normally and the help text will only be shown when editing
    return customization || helpText ? <Element dangerouslySetInnerHTML={{__html: customization ? customization.content : defaultText}}></Element> : <Element className={"text-muted"} dangerouslySetInnerHTML={{__html: '[' + defaultText + ']'}}/>
}

function AdvancementScript({context}: { context: AwardPresentationContext }) {
    if(!context.advancementConfig || context.advancementConfig.advancementCount == 0) {
        return null;
    }
    const advancementCount = context.advancementConfig.advancementCount;
    const applicableAdvancements = filterAdvancements(context.advancements, context.advancementConfig.advancementCount);
    return <div>
        <div className="mr-1 d-inline-block award-name"><b>Advancement</b></div>
        <p>And now I'm excited to announce the {ngettext(msgid`${advancementCount} team`, `${advancementCount} teams`, advancementCount)} advancing
            from this event to {context.advancementConfig.advancesTo}{context.advancementConfig.reserveCount > 0 ? `, including up to ${context.advancementConfig.reserveCount} to FIRST Championship,` : null} based on their combined point totals after their on-field and judging performance today</p>
        {/* TODO adjust for points-based advancement */}
        {applicableAdvancements.map((a, idx) => <p key={idx}>
            {idx == 0 ? <span>The first advancement slot goes to:</span> : <span>The next advancement slot goes to:</span>}
            <div className="ml-5 award-winners">
                <b>{a.displayTeam} {a.teamName}</b>
                {a.status == AdvancementStatus.INELIGIBLE ? ", who is not eligible to advance from this event" : ""}
                {a.status == AdvancementStatus.ALREADY_ADVANCING ? ", who has already advanced from another event" : ""}
                {a.status == AdvancementStatus.ADVANCING_ABOVE ? ", who has already advanced from this event" : ""}
                {a.team == -1 ? "Which does not exist at this event" : ""}
            </div>
        </p>)}
        <StageDirection>applause</StageDirection>
        <hr/>
    </div>;
}

